import { AnnotationsMarkerConfig } from '../types/annotations-marker-props.js';

/**
 * Defines the main color of the marker depending on priority.
 * If all of them have the same priority, or no priority is set, the first color will be returned
 *
 * @param markers -
 *
 * @returns color(string)
 */
export function defineMarkerColor(markers: AnnotationsMarkerConfig[]): string {
  let topPriorityMarker = markers[0];

  for (let i = 1; i < markers.length; i++) {
    if (markers[i].priority > topPriorityMarker.priority) {
      topPriorityMarker = markers[i];
    }
  }

  return topPriorityMarker.color;
}
